<?php
namespace App\Domain\Accounting\Actions;
use App\Enums\JournalStatus;use App\Models\AccountingPeriod;use App\Models\Branch;use App\Models\JournalEntry;use App\Models\LedgerAccount;use App\Models\Loan;use App\Models\Member;use Carbon\CarbonImmutable;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\DB;use Illuminate\Support\Str;use Illuminate\Validation\ValidationException;
class PostJournal{public function execute(array $data):JournalEntry{$date=CarbonImmutable::parse($data['entry_date']);$period=AccountingPeriod::query()->where('status','open')->whereDate('start_date','<=',$date)->whereDate('end_date','>=',$date)->first();if(!$period)throw ValidationException::withMessages(['entry_date'=>['No open accounting period contains this date.']]);$debits=(int)collect($data['lines'])->sum('debit_minor');$credits=(int)collect($data['lines'])->sum('credit_minor');if($debits<=0||$debits!==$credits)throw ValidationException::withMessages(['lines'=>['Journal debits and credits must be equal and greater than zero.']]);foreach($data['lines'] as $index=>$line){if(((int)$line['debit_minor']>0)===((int)$line['credit_minor']>0))throw ValidationException::withMessages(["lines.{$index}"=>['A line must contain either a debit or a credit, never both.']]);$account=LedgerAccount::query()->findOrFail($line['ledger_account_id']);if(!$account->is_active||!$account->allows_direct_posting)throw ValidationException::withMessages(["lines.{$index}.ledger_account_id"=>['This account does not allow direct posting.']]);if(!empty($line['member_id']))Member::query()->findOrFail($line['member_id']);if(!empty($line['loan_id']))Loan::query()->findOrFail($line['loan_id']);if(!empty($line['branch_id']))Branch::query()->findOrFail($line['branch_id']);}return DB::transaction(function()use($data,$period,$debits,$credits){$entry=JournalEntry::query()->create(['accounting_period_id'=>$period->id,'reversal_of_id'=>$data['reversal_of_id']??null,'reference'=>$data['reference']??'JRN-'.strtoupper(Str::ulid()),'entry_date'=>$data['entry_date'],'source_type'=>$data['source_type']??null,'source_id'=>$data['source_id']??null,'event_type'=>$data['event_type']??null,'description'=>$data['description'],'currency'=>$data['currency']??'NGN','total_debit_minor'=>$debits,'total_credit_minor'=>$credits,'status'=>JournalStatus::Posted,'posted_by'=>Auth::id(),'posted_at'=>now(),'metadata'=>$data['metadata']??null]);foreach($data['lines'] as $line)$entry->lines()->create($line);return $entry->load('lines.account');});}}
